const p = $json.body || $json;
const m = p.metrics || {};
const emo = Object.entries(m.emotion || {}).map(([k,v]) => `${k} ${v}`).join(' · ') || '없음';
const cov = m.coverage ? `${(m.coverage.covered||[]).length}/${m.coverage.total}` : '-';
let transcript = p.transcript || '';
if (transcript.length > 1000) transcript = transcript.slice(0, 1000) + '…';
const embed = {
  title: `새 인터뷰 응답 · ${p.project?.title || p.project?.id || ''}`,
  description: p.summary || '(요약 없음)',
  url: (p.dashboard_url && p.dashboard_url.indexOf('http') === 0) ? p.dashboard_url : undefined,
  fields: [
    { name: '감정', value: emo, inline: true },
    { name: '커버리지', value: cov, inline: true },
    { name: '진행자 질문', value: String(p.session?.asked ?? '-'), inline: true },
    { name: '전사', value: '```\n' + (transcript || '(없음)') + '\n```' }
  ]
};
return [{ json: { content: null, embeds: [embed] } }];
